#include <iostream>
#include <string>
#include <string_view>

class CPU
{
    std::string m_model;
    int m_cores{};
public:
    CPU(std::string_view model, int cores)
        : m_model{ model }, m_cores{ cores } {}
    std::string describe() const
    {
        return m_model + " (" + std::to_string(m_cores) + " cores)";
    }
};

class Memory
{
    int m_sizeGB{};
public:
    Memory(int sizeGB) : m_sizeGB{ sizeGB } {}
    std::string describe() const
    {
        return std::to_string(m_sizeGB) + "GB";
    }
};

class Computer
{
    CPU m_cpu;
    Memory m_memory;
public:
    Computer(const CPU& cpu, const Memory& memory)
        : m_cpu{ cpu }, m_memory{ memory } {}
    void printSpecs() const
    {
        std::cout << "CPU: " << m_cpu.describe() << '\n';
        std::cout << "Memory: " << m_memory.describe() << '\n';
        std::cout << "Computer built\n";
    }
};

int main()
{
    std::string cpuModel{};
    int cores{};
    std::cin >> cpuModel >> cores;
    int sizeGB{};
    std::cin >> sizeGB;
    Computer computer{ CPU{ cpuModel, cores }, Memory{ sizeGB } };
    computer.printSpecs();
    return 0;
}
